from flask import Flask, request
import psycopg2
from psycopg2.extras import execute_cursor

app = Flask(__name__)

def build_query(table_name, columns, filter_conditions):
    query = "SELECT "
    query += ", ".join(columns)
    query += " FROM "
    query += table_name
    if filter_conditions:
        query += " WHERE "
        conditions = []
        for condition in filter_conditions:
            column, operator, value = condition
            conditions.append(f"{column} {operator} '{value}'")
        query += " AND ".join(conditions)
    return query

def execute_query(query):
    conn = psycopg2.connect(
        host="your_host",
        database="your_database",
        user="your_user",
        password="your_password"
    )
    cur = conn.cursor()
    try:
        execute_cursor(cur, query)
        results = cur.fetchall()
        columns = [desc[0] for desc in cur.description]
        return {"columns": columns, "data": results}
    except psycopg2.Error as e:
        print(f"Error: {e}")
        return {"error": str(e)}
    finally:
        conn.close()

@app.route('/api/data', methods=['GET'])
def get_data():
    table_name = request.args.get('table')
    if not table_name:
        return {"error": "Table name is required"}, 400
    columns = [col.strip() for col in request.args.getlist('columns')]
    filter_conditions = []
    conditions = request.args.get('filter', default='')
    if conditions:
        conditions = conditions.split(',')
        for condition in conditions:
            column, operator, value = condition.split(':')
            filter_conditions.append((column, operator, value.strip()))
    query = build_query(table_name, columns, filter_conditions)
    results = execute_query(query)
    return results

if __name__ == '__main__':
    app.run(debug=True)